parameters.jsCode:
const groups = new Map();

for (const item of $input.all()) {
  const row = item.json;

  const hasUpload = !!row.download_url;
  const docNames = hasUpload
    ? (row["Documents (from uploadLinkId)"] || [])
    : (row.name ? [row.name] : []);

  for (const doc of docNames) {
    if (!doc) continue;

    if (!groups.has(doc)) {
      groups.set(doc, new Set());
    }

    if (hasUpload) {
      groups.get(doc).add(row.download_url);
    }
  }
}

const result = Array.from(groups.entries()).map(([document, urlsSet]) => ({
  document,
  download_urls: Array.from(urlsSet),
}));

result.sort((a, b) => a.document.localeCompare(b.document));

return [{ json: { documents: result } }];

